ALTER TABLE public.cb_beneficios ADD COLUMN IF NOT EXISTS grupo_gratuidade text;
CREATE INDEX IF NOT EXISTS idx_cb_beneficios_grupo_gratuidade ON public.cb_beneficios (clinica_id, convenio_id, grupo_gratuidade) WHERE grupo_gratuidade IS NOT NULL;
COMMENT ON COLUMN public.cb_beneficios.grupo_gratuidade IS 'Identificador do grupo de gratuidade compartilhada. Regras com o mesmo valor dividem a mesma cota (limite_qtd) no contrato — ex.: mama-preventivo cobre Mamografia OU USG Mama. NULL = sem compartilhamento (comportamento padrão por procedimento).';